// ============================================
// components/MapView.js - Leaflet Map Component
// ============================================
// Free OpenStreetMap tiles - No API key needed!
// Dynamic import se use karo (ssr: false)
// Loads Leaflet from CDN if npm package not available

import { useEffect, useRef, useState } from 'react';

// Helper: Load Leaflet (npm first, fallback to CDN)
function loadLeaflet() {
  return import('leaflet').catch(() => {
    // npm package not found → load from CDN
    return new Promise((resolve, reject) => {
      if (window.L) { resolve(window.L); return; }
      const script = document.createElement('script');
      script.src = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.js';
      script.onload = () => resolve(window.L);
      script.onerror = () => reject(new Error('Failed to load Leaflet'));
      document.head.appendChild(script);
    });
  });
}

export default function MapView({ locations = [], selectedScan, onSelectScan, qrInfo }) {
  const mapRef = useRef(null);
  const leafletMapRef = useRef(null);
  const markersRef = useRef([]);
  const polylineRef = useRef(null);

  useEffect(() => {
    if (typeof window === 'undefined' || !mapRef.current) return;
    if (leafletMapRef.current) return;

    loadLeaflet().then(L => {
      // Fix default marker icons
      delete L.Icon.Default.prototype._getIconUrl;
      L.Icon.Default.mergeOptions({
        iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
        iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
        shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
      });

      const map = L.map(mapRef.current, {
        zoomControl: true,
        attributionControl: false,
      }).setView([20.5937, 78.9629], 5);

      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        maxZoom: 19,
      }).addTo(map);

      leafletMapRef.current = map;
      addMarkers(L, map, locations);
    }).catch(err => {
      console.error('Leaflet load error:', err);
    });

    return () => {
      if (leafletMapRef.current) {
        leafletMapRef.current.remove();
        leafletMapRef.current = null;
      }
    };
  }, []);

  useEffect(() => {
    if (!leafletMapRef.current || locations.length === 0) return;
    loadLeaflet().then(L => {
      addMarkers(L, leafletMapRef.current, locations);
    });
  }, [locations]);

  useEffect(() => {
    if (!leafletMapRef.current || !selectedScan) return;
    if (selectedScan.latitude && selectedScan.longitude) {
      leafletMapRef.current.flyTo([selectedScan.latitude, selectedScan.longitude], 14, { duration: 1.2 });
    }
  }, [selectedScan]);

  const addMarkers = (L, map, locs) => {
    markersRef.current.forEach(m => m.remove());
    markersRef.current = [];
    if (polylineRef.current) { polylineRef.current.remove(); polylineRef.current = null; }

    const validLocs = locs.filter(l => l.latitude && l.longitude && l.latitude !== 0);
    if (validLocs.length === 0) return;

    const points = [];

    validLocs.forEach((loc, i) => {
      const isLatest = i === 0;
      const lat = loc.latitude;
      const lng = loc.longitude;
      points.push([lat, lng]);

      const iconHtml = isLatest
        ? `<div style="background:linear-gradient(135deg,#6366f1,#a855f7);width:28px;height:28px;border-radius:50% 50% 50% 0;transform:rotate(-45deg);border:2px solid white;box-shadow:0 2px 8px rgba(99,102,241,0.6)"></div>`
        : `<div style="background:rgba(99,102,241,0.6);width:14px;height:14px;border-radius:50%;border:2px solid rgba(99,102,241,0.9)"></div>`;

      const icon = L.divIcon({
        html: iconHtml,
        className: '',
        iconSize: isLatest ? [28, 28] : [14, 14],
        iconAnchor: isLatest ? [14, 28] : [7, 7],
      });

      const marker = L.marker([lat, lng], { icon })
        .addTo(map)
        .bindPopup(`
          <div style="font-family:sans-serif;min-width:160px">
            <b style="color:#6366f1">${isLatest ? '🔴 Latest Scan' : `#${i + 1}`}</b><br/>
            <small>📍 ${loc.address?.city || 'Unknown'}, ${loc.address?.country || ''}</small><br/>
            <small>📱 ${loc.device?.deviceType || 'Device'} | ${loc.device?.os || ''}</small><br/>
            <small>⏰ ${new Date(loc.scannedAt).toLocaleString('en-IN')}</small>
            ${loc.isApproximate ? '<br/><small style="color:orange">⚠️ Approximate location</small>' : ''}
          </div>
        `, { maxWidth: 220 });

      marker.on('click', () => { if (onSelectScan) onSelectScan(loc); });
      markersRef.current.push(marker);
    });

    if (points.length > 1) {
      polylineRef.current = L.polyline(points, {
        color: '#6366f1',
        weight: 2,
        opacity: 0.5,
        dashArray: '6, 6',
      }).addTo(map);
    }

    const bounds = L.latLngBounds(points);
    map.fitBounds(bounds, { padding: [40, 40], maxZoom: 13 });
  };

  return (
    <div className="relative w-full h-full">
      <link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css" />
      <style jsx global>{`
        .leaflet-container { background: #1a1a2e; }
        .leaflet-popup-content-wrapper { background: rgba(15,15,45,0.95); color: #e0e0f0; border: 1px solid rgba(99,102,241,0.3); border-radius: 12px; }
        .leaflet-popup-tip { background: rgba(15,15,45,0.95); }
        .leaflet-control-zoom a { background: rgba(15,15,45,0.95) !important; color: #e0e0f0 !important; border-color: rgba(99,102,241,0.3) !important; }
      `}</style>

      <div ref={mapRef} style={{ width: '100%', height: '100%' }} />

      {locations.length > 0 && (
        <div className="absolute top-3 right-3 z-[1000] bg-[rgba(15,15,45,0.9)] border border-indigo-500/30 rounded-xl px-3 py-2 text-[10px] text-gray-300 font-bold shadow-xl">
          📍 {locations.filter(l => l.latitude).length} locations
        </div>
      )}

      {locations.filter(l => l.latitude).length === 0 && (
        <div className="absolute inset-0 flex items-center justify-center z-[1000] pointer-events-none">
          <div className="bg-[rgba(15,15,45,0.9)] border border-indigo-500/20 rounded-2xl p-6 text-center">
            <span className="text-3xl block mb-2">🗺️</span>
            <p className="text-sm text-gray-400">No GPS locations found yet</p>
            <p className="text-[10px] text-gray-600 mt-1">When QR is scanned with GPS, it will show on the map</p>
          </div>
        </div>
      )}
    </div>
  );
}
